-- Import missing clients from OLD CRM (88 rows)
-- Uses temp table + anti-join to skip existing id AND phone_normalized matches
BEGIN;

CREATE TEMP TABLE _old_clients (
  id uuid, agent_id uuid, full_name text, phone text, email text,
  nin_cin text, birth_date date, nationality text, profession text,
  source client_source, desired_unit_types text[], interested_projects text[],
  confirmed_budget numeric, interest_level interest_level,
  visit_note numeric, visit_feedback text, notes text, created_at timestamptz
) ON COMMIT DROP;


-- Helper: normalize phone the same way the trigger does (strip non-digits, drop leading country code keeping last 9-10)
-- We'll match against existing clients.phone_normalized to avoid UNIQUE conflict.
  id, agent_id, full_name, phone, email, nin_cin, birth_date, nationality, profession,
  source, desired_unit_types, interested_projects, confirmed_budget, interest_level,
  visit_note, visit_feedback, notes, created_at
)
SELECT o.id, o.agent_id, o.full_name, o.phone, o.email, o.nin_cin, o.birth_date,
       o.nationality, o.profession, o.source, o.desired_unit_types, o.interested_projects,
       o.confirmed_budget, o.interest_level, o.visit_note, o.visit_feedback, o.notes, o.created_at
  FROM _old_clients o
 WHERE NOT EXISTS (SELECT 1 FROM public.clients c WHERE c.id = o.id)
   AND NOT EXISTS (
         SELECT 1 FROM public.clients c
          WHERE c.phone_normalized IS NOT NULL
            AND c.phone_normalized = public.normalize_phone(o.phone)
       );

-- Report results
SELECT
  (SELECT COUNT(*) FROM _old_clients) AS old_total,
  (SELECT COUNT(*) FROM public.clients WHERE agent_id = '09daa9d0-3c8f-49fb-909f-24da5563908b') AS current_soumeya,
  (SELECT COUNT(*) FROM _old_clients o
    WHERE EXISTS (SELECT 1 FROM public.clients c WHERE c.id = o.id)) AS matched_by_id,
  (SELECT COUNT(*) FROM _old_clients o
    WHERE NOT EXISTS (SELECT 1 FROM public.clients c WHERE c.id = o.id)
      AND EXISTS (SELECT 1 FROM public.clients c
                   WHERE c.phone_normalized = public.normalize_phone(o.phone))) AS matched_by_phone_only;

COMMIT;
